    ${lead.moveDate ? `<p><strong>Move Date:</strong> ${lead.moveDate}</p>` : ''}
    ${lead.propertySize ? `<p><strong>Property Size:</strong> ${lead.propertySize}</p>` : ''}
    ${lead.details ? `<p><strong>Additional Details:</strong> ${lead.details}</p>` : ''}
