import * as React from "react"
import useEmblaCarousel, {
  type UseEmblaCarouselType,
} from "embla-carousel-react"
import { ArrowLeft, ArrowRight } from "lucide-react"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"

type CarouselApi = UseEmblaCarouselType[1]
type UseCarouselParameters = Parameters<typeof useEmblaCarousel>
type CarouselOptions = UseCarouselParameters[0]
type CarouselPlugin = UseCarouselParameters[1]

type CarouselProps = {
  opts?: CarouselOptions
  plugins?: CarouselPlugin
  orientation?: "horizontal" | "vertical"
  setApi?: (api: CarouselApi) => void
}

type CarouselContextProps = {
  carouselRef: ReturnType<typeof useEmblaCarousel>[0]
  api: ReturnType<typeof useEmblaCarousel>[1]
  scrollPrev: () => void
  scrollNext: () => void
  canScrollPrev: boolean
  canScrollNext: boolean
} & CarouselProps

const CarouselContext = React.createContext<CarouselContextProps | null>(null)

function useCarousel() {
  const context = React.useContext(CarouselContext)

  if (!context) {
    throw new Error("useCarousel must be used within a <Carousel />")
  }

  return context
}

const Carousel = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & CarouselProps
>(
  (
    {
      orientation = "horizontal",
      opts,
      setApi,
      plugins,
      className,
      children,
      ...props
    },
    ref
  ) => {
    const [carouselRef, api] = useEmblaCarousel(
      {
        ...opts,
        axis: orientation === "horizontal" ? "x" : "y",
      },
      plugins
    )
    const [canScrollPrev, setCanScrollPrev] = React.useState(false)
    const [canScrollNext, setCanScrollNext] = React.useState(false)

    const onSelect = React.useCallback((api: CarouselApi) => {
      if (!api) {
        return
      }

      setCanScrollPrev(api.canScrollPrev())
      setCanScrollNext(api.canScrollNext())
    }, [])

    const scrollPrev = React.useCallback(() => {
      api?.scrollPrev()
    }, [api])

    const scrollNext = React.useCallback(() => {
      api?.scrollNext()
    }, [api])

    const handleKeyDown = React.useCallback(
      (event: React.KeyboardEvent<HTMLDivElement>) => {
        if (event.key === "ArrowLeft") {
          event.preventDefault()
          scrollPrev()
        } else if (event.key === "ArrowRight") {
          event.preventDefault()
          scrollNext()
        }
      },
      [scrollPrev, scrollNext]
    )

    React.useEffect(() => {
      if (!api || !setApi) {
        return
      }

      setApi(api)
    }, [api, setApi])

    React.useEffect(() => {
      if (!api) {
        return
      }

      onSelect(api)
      api.on("reInit", onSelect)
      api.on("select", onSelect)

      return () => {
        api?.off("select", onSelect)
      }
    }, [api, onSelect])

    return (
      <CarouselContext.Provider
        value={{
          carouselRef,
          api: api,
          opts,
          orientation:
            orientation || (opts?.axis === "y" ? "vertical" : "horizontal"),
          scrollPrev,
          scrollNext,
          canScrollPrev,
          canScrollNext,
        }}
      >
        <div
          ref={ref}
          onKeyDownCapture={handleKeyDown}
          className={cn("relative", className)}
          role="region"
          aria-roledescription="carousel"
          {...props}
        >
          {children}
        </div>
      </CarouselContext.Provider>
    )
  }
)
Carousel.displayName = "Carousel"

const CarouselContent = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => {
  const { carouselRef, orientation } = useCarousel()

  return (
    <div ref={carouselRef} className="overflow-hidden">
      <div
        ref={ref}
        className={cn(
          "flex",
          orientation === "horizontal" ? "-ml-4" : "-mt-4 flex-col",
          className
        )}
        {...props}
      />
    </div>
  )
})
CarouselContent.displayName = "CarouselContent"

const CarouselItem = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => {
  const { orientation } = useCarousel()

  return (
    <div
      ref={ref}
      role="group"
      aria-roledescription="slide"
      className={cn(
        "min-w-0 shrink-0 grow-0 basis-full",
        orientation === "horizontal" ? "pl-4" : "pt-4",
        className
      )}
      {...props}
    />
  )
})
CarouselItem.displayName = "CarouselItem"

const CarouselPrevious = React.forwardRef<
  HTMLButtonElement,
  React.ComponentProps<typeof Button>
>(({ className, variant = "outline", size = "icon", ...props }, ref) => {
  const { orientation, scrollPrev, canScrollPrev } = useCarousel()

  return (
    <Button
      ref={ref}
      variant={variant}
      size={size}
      className={cn(
        "absolute  h-8 w-8 rounded-full",
        orientation === "horizontal"
          ? "-left-12 top-1/2 -translate-y-1/2"
          : "-top-12 left-1/2 -translate-x-1/2 rotate-90",
        className
      )}
      disabled={!canScrollPrev}
      onClick={scrollPrev}
      {...props}
    >
      <ArrowLeft className="h-4 w-4" />
      <span className="sr-only">Previous slide</span>
    </Button>
  )
})
CarouselPrevious.displayName = "CarouselPrevious"

const CarouselNext = React.forwardRef<
  HTMLButtonElement,
  React.ComponentProps<typeof Button>
>(({ className, variant = "outline", size = "icon", ...props }, ref) => {
  const { orientation, scrollNext, canScrollNext } = useCarousel()

  return (
    <Button
      ref={ref}
      variant={variant}
      size={size}
      className={cn(
        "absolute h-8 w-8 rounded-full",
        orientation === "horizontal"
          ? "-right-12 top-1/2 -translate-y-1/2"
          : "-bottom-12 left-1/2 -translate-x-1/2 rotate-90",
        className
      )}
      disabled={!canScrollNext}
      onClick={scrollNext}
      {...props}
    >
      <ArrowRight className="h-4 w-4" />
      <span className="sr-only">Next slide</span>
    </Button>
  )
})
CarouselNext.displayName = "CarouselNext"

export {
  type CarouselApi,
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselPrevious,
  CarouselNext,
}

client/src/pages/create-shop-item.tsx.content:
import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { insertShopItemSchema, type InsertShopItem } from "@shared/schema";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { ChevronLeft, ChevronRight, X, Upload, Loader2 } from "lucide-react";
import { z } from "zod";

// Form schema for client-side validation
// Updated to accept both URLs and base64 data URLs for photo uploads
const formSchema = z.object({
  title: z.string().min(1, "Title is required").max(200),
  description: z.string().min(1, "Description is required"),
  price: z.string().min(1, "Price is required").regex(/^\d+(\.\d{1,2})?$/, "Invalid price format (e.g., 10.99)"),
  phoneNumber: z.string().min(1, "Phone number is required").regex(/^[\d\s\-\(\)\+]+$/, "Invalid phone number format"),
  photos: z.array(
    z.string()
      .refine(
        (val) => val.startsWith("http://") || val.startsWith("https://") || val.startsWith("data:image/"),
        { message: "Must be a valid URL or image file" }
      )
  ).min(1, "At least one photo is required").max(10, "Maximum 10 photos allowed"),
  status: z.enum(["draft", "active", "sold", "archived"]),
  category: z.string().optional(),
});

type FormData = z.infer<typeof formSchema>;

export function CreateShopItemPage() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [photoUrls, setPhotoUrls] = useState<string[]>([]);
  const [currentPhotoIndex, setCurrentPhotoIndex] = useState(0);
  const [photoInputValue, setPhotoInputValue] = useState("");

  const form = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      title: "",
      description: "",
      price: "",
      phoneNumber: "",
      photos: [],
      status: "draft",
      category: "",
    },
  });

  const createItemMutation = useMutation({
    mutationFn: async (data: FormData) => {
      const response = await apiRequest("POST", "/api/shop", data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/shop"] });
      toast({
        title: "Success!",
        description: "Your item has been posted to the shop.",
      });
      setLocation("/shop");
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to create shop item. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleAddPhoto = () => {
    if (!photoInputValue) return;

    // Check if already at 10-photo limit
    if (photoUrls.length >= 10) {
      toast({
        title: "Photo limit reached",
        description: "Maximum 10 photos allowed",
        variant: "destructive",
      });
      return;
    }

    // Check for duplicate
    if (photoUrls.includes(photoInputValue)) {
      toast({
        title: "Duplicate photo",
        description: "This photo URL has already been added",
      });
      return;
    }

    const newPhotos = [...photoUrls, photoInputValue];
    setPhotoUrls(newPhotos);
    form.setValue("photos", newPhotos);
    setPhotoInputValue("");
    setCurrentPhotoIndex(newPhotos.length - 1);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const fileArray = Array.from(files);
    const validFiles: File[] = [];

    // Validate all files first
    for (const file of fileArray) {
      // Check file size (max 25MB to support 40MP photos)
      if (file.size > 25 * 1024 * 1024) {
        toast({
          title: "File too large",
          description: `${file.name} exceeds 25MB limit`,
          variant: "destructive",
        });
        continue;
      }

      // Check file type
      if (!file.type.startsWith('image/')) {
        toast({
          title: "Invalid file type",
          description: `${file.name} is not an image`,
          variant: "destructive",
        });
        continue;
      }

      validFiles.push(file);
    }

    // Convert all valid files to base64
    const base64Results: string[] = [];
    for (const file of validFiles) {
      try {
        const base64String = await new Promise<string>((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = (event) => {
            const result = event.target?.result as string;
            resolve(result);
          };
          reader.onerror = () => reject(new Error(`Failed to read ${file.name}`));
          reader.readAsDataURL(file);
        });
        base64Results.push(base64String);
      } catch (error) {
        toast({
          title: "Upload failed",
          description: error instanceof Error ? error.message : `Failed to read ${file.name}`,
          variant: "destructive",
        });
      }
    }

    // Update state with all new photos at once
    if (base64Results.length > 0) {
      setPhotoUrls(prevPhotos => {
        // Filter out duplicates - check against both existing and newly added photos
        const uniqueNewPhotos = base64Results.filter((photo, index, self) => 
          !prevPhotos.includes(photo) && self.indexOf(photo) === index
        );

        if (uniqueNewPhotos.length === 0) {
          toast({
            title: "No new photos",
            description: "All selected photos were already added",
          });
          return prevPhotos;
        }

        const newPhotos = [...prevPhotos, ...uniqueNewPhotos].slice(0, 10);
        form.setValue("photos", newPhotos);
        setCurrentPhotoIndex(newPhotos.length - 1);

        if (prevPhotos.length + uniqueNewPhotos.length > 10) {
          toast({
            title: "Photo limit reached",
            description: `Added ${newPhotos.length - prevPhotos.length} of ${uniqueNewPhotos.length} photos. Maximum 10 photos allowed.`,
            variant: "destructive",
          });
        }

        return newPhotos;
      });
    }

    // Reset input
    e.target.value = '';
  };

  const handleRemovePhoto = (index: number) => {
    const newPhotos = photoUrls.filter((_, i) => i !== index);
    setPhotoUrls(newPhotos);
    form.setValue("photos", newPhotos);
    if (currentPhotoIndex >= newPhotos.length && newPhotos.length > 0) {
      setCurrentPhotoIndex(newPhotos.length - 1);
    } else if (newPhotos.length === 0) {
      setCurrentPhotoIndex(0);
    }
  };

  const handlePrevPhoto = () => {
    setCurrentPhotoIndex((prev) => (prev > 0 ? prev - 1 : photoUrls.length - 1));
  };

  const handleNextPhoto = () => {
    setCurrentPhotoIndex((prev) => (prev < photoUrls.length - 1 ? prev + 1 : 0));
  };

  const onSubmit = (data: FormData) => {
    createItemMutation.mutate(data);
  };

  return (
    <div className="container max-w-3xl mx-auto py-8 px-4">
      <Card>
        <CardHeader>
          <CardTitle>Post New Item</CardTitle>
          <CardDescription>
            Share items you want to sell with the community. Add photos, set a price, and publish when ready.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              {/* Photos Section with Slideshow Preview */}
              <div className="space-y-4">
                <FormLabel>Photos</FormLabel>

                {/* Photo Slideshow Preview */}
                {photoUrls.length > 0 && (
                  <div className="relative bg-muted rounded-lg aspect-video overflow-hidden">
                    <img
                      src={photoUrls[currentPhotoIndex]}
                      alt={`Photo ${currentPhotoIndex + 1}`}
                      className="w-full h-full object-contain"
                      data-testid={`img-preview-${currentPhotoIndex}`}
                    />

                    {/* Navigation Arrows */}
                    {photoUrls.length > 1 && (
                      <>
                        <button
                          type="button"
                          onClick={handlePrevPhoto}
                          className="absolute left-2 top-1/2 -translate-y-1/2 bg-black/50 hover:bg-black/70 text-white p-2 rounded-full transition-colors"
                          data-testid="button-prev-photo"
                        >
                          <ChevronLeft className="h-5 w-5" />
                        </button>
                        <button
                          type="button"
                          onClick={handleNextPhoto}
                          className="absolute right-2 top-1/2 -translate-y-1/2 bg-black/50 hover:bg-black/70 text-white p-2 rounded-full transition-colors"
                          data-testid="button-next-photo"
                        >
                          <ChevronRight className="h-5 w-5" />
                        </button>
                      </>
                    )}

                    {/* Photo Counter */}
                    <div className="absolute bottom-2 right-2 bg-black/50 text-white px-3 py-1 rounded-full text-sm">
                      {currentPhotoIndex + 1} / {photoUrls.length}
                    </div>

                    {/* Remove Photo Button */}
                    <button
                      type="button"
                      onClick={() => handleRemovePhoto(currentPhotoIndex)}
                      className="absolute top-2 right-2 bg-red-500 hover:bg-red-600 text-white p-2 rounded-full transition-colors"
                      data-testid={`button-remove-photo-${currentPhotoIndex}`}
                    >
                      <X className="h-4 w-4" />
                    </button>
                  </div>
                )}

                {/* Photo Upload Options */}
                <div className="space-y-3">
                  {/* File Upload Button */}
                  <div className="flex gap-2">
                    <Input
                      type="file"
                      accept="image/*"
                      multiple
                      onChange={handleFileUpload}
                      className="hidden"
                      id="photo-file-input"
                      data-testid="input-photo-file"
                    />
                    <Button
                      type="button"
                      onClick={() => document.getElementById('photo-file-input')?.click()}
                      variant="outline"
                      className="flex-1"
                      data-testid="button-upload-photo"
                    >
                      <Upload className="h-4 w-4 mr-2" />
                      Upload from Device
                    </Button>
                  </div>

                  {/* URL Input */}
                  <div className="flex gap-2">
                    <Input
                      placeholder="Or enter photo URL (e.g., https://...)"
                      value={photoInputValue}
                      onChange={(e) => setPhotoInputValue(e.target.value)}
                      onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddPhoto())}
                      data-testid="input-photo-url"
                    />
                    <Button
                      type="button"
                      onClick={handleAddPhoto}
                      disabled={!photoInputValue}
                      data-testid="button-add-photo"
                    >
                      Add URL
                    </Button>
                  </div>
                </div>

                <FormDescription>
                  Add up to 10 photos (max 25MB each, supports 40MP images). Upload from your device or paste image URLs. Photos will appear in a slideshow.
                </FormDescription>
                {form.formState.errors.photos && (
                  <p className="text-sm font-medium text-destructive">{form.formState.errors.photos.message}</p>
                )}
              </div>

              {/* Title Field */}
              <FormField
                control={form.control}
                name="title"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Title</FormLabel>
                    <FormControl>
                      <Input placeholder="e.g., Vintage Leather Couch" {...field} data-testid="input-title" />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Description Field */}
              <FormField
                control={form.control}
                name="description"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Description</FormLabel>
                    <FormControl>
                      <Textarea
                        placeholder="Describe the item, its condition, features, etc."
                        className="min-h-[120px]"
                        {...field}
                        data-testid="textarea-description"
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Price, Phone Number, and Category Row */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {/* Price Field */}
                <FormField
                  control={form.control}
                  name="price"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Price ($)</FormLabel>
                      <FormControl>
                        <Input
                          type="text"
                          placeholder="0.00"
                          {...field}
                          data-testid="input-price"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                {/* Phone Number Field */}
                <FormField
                  control={form.control}
                  name="phoneNumber"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Contact Phone Number</FormLabel>
                      <FormControl>
                        <Input
                          type="tel"
                          placeholder="(517) 202-5454"
                          {...field}
                          data-testid="input-phone-number"
                        />
                      </FormControl>
                      <FormDescription className="text-xs">
                        Buyers will see this number to contact you
                      </FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              {/* Category Field */}
              <FormField
                control={form.control}
                name="category"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Category (Optional)</FormLabel>
                    <FormControl>
                      <Input
                        placeholder="e.g., Furniture, Electronics"
                        {...field}
                        data-testid="input-category"
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Status Field */}
              <FormField
                control={form.control}
                name="status"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Status</FormLabel>
                    <Select onValueChange={field.onChange} defaultValue={field.value}>
                      <FormControl>
                        <SelectTrigger data-testid="select-status">
                          <SelectValue placeholder="Select status" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        <SelectItem value="draft">Draft (Not visible to others)</SelectItem>
                        <SelectItem value="active">Active (Visible to everyone)</SelectItem>
                        <SelectItem value="sold">Sold</SelectItem>
                        <SelectItem value="archived">Archived</SelectItem>
                      </SelectContent>
                    </Select>
                    <FormDescription>
                      Draft items are only visible to you. Active items are visible to all users.
                    </FormDescription>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Submit Buttons */}
              <div className="flex gap-3">
                <Button
                  type="submit"
                  disabled={createItemMutation.isPending}
                  className="flex-1"
                  data-testid="button-submit"
                >
                  {createItemMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  Post Item
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => setLocation("/shop")}
                  disabled={createItemMutation.isPending}
                  data-testid="button-cancel"
                >
                  Cancel
                </Button>
              </div>
            </form>
          </Form>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/pages/shop-item-detail.tsx.content:
import { useState } from "react";
import { useParams, useLocation } from "wouter";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { ChevronLeft, ChevronRight, ArrowLeft, Eye, MessageCircle, DollarSign, X, Phone, Trash2, CheckCircle2, Pencil } from "lucide-react";
import { type ShopItem } from "@shared/schema";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import { apiRequest, queryClient } from "@/lib/queryClient";

export function ShopItemDetailPage() {
  const { id } = useParams();
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const { user } = useAuth();
  const [currentMediaIndex, setCurrentMediaIndex] = useState(0);
  const [isZoomOpen, setIsZoomOpen] = useState(false);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editTitle, setEditTitle] = useState("");
  const [editDescription, setEditDescription] = useState("");
  const [editPrice, setEditPrice] = useState("");
  const [editCategory, setEditCategory] = useState("");

  // Fetch shop item details
  const { data: item, isLoading } = useQuery<ShopItem>({
    queryKey: ["/api/shop", id],
    enabled: !!id,
  });

  // Delete mutation
  const deleteMutation = useMutation({
    mutationFn: async () => {
      return await apiRequest("DELETE", `/api/shop/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/shop"] });
      toast({
        title: "Item Deleted",
        description: "Your shop item has been removed.",
      });
      setLocation("/shop");
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to delete item",
        variant: "destructive",
      });
    },
  });

  // Mark as sold mutation
  const markAsSoldMutation = useMutation({
    mutationFn: async () => {
      return await apiRequest("PATCH", `/api/shop/${id}`, { status: "sold" });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/shop", id] });
      queryClient.invalidateQueries({ queryKey: ["/api/shop"] });
      toast({
        title: "Marked as Sold",
        description: "This item is now marked as sold.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to update item status",
        variant: "destructive",
      });
    },
  });

  const updateMutation = useMutation({
    mutationFn: async (data: any) => {
      return await apiRequest("PATCH", `/api/shop/${id}`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/shop", id] });
      queryClient.invalidateQueries({ queryKey: ["/api/shop"] });
      setIsEditOpen(false);
      toast({ title: "Item Updated", description: "Your changes have been saved." });
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message || "Failed to update item", variant: "destructive" });
    },
  });

  const startEdit = () => {
    if (!item) return;
    setEditTitle(item.title);
    setEditDescription(item.description);
    setEditPrice(item.price);
    setEditCategory(item.category || "");
    setIsEditOpen(true);
  };

  const handleUpdate = () => {
    updateMutation.mutate({
      title: editTitle,
      description: editDescription,
      price: editPrice,
      category: editCategory || undefined,
    });
  };

  // Check if user can manage this item (creator or admin)
  const canManageItem = item && user && (item.postedBy === user.id || user.role === 'admin');

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background p-4">
        <Skeleton className="h-8 w-32 mb-4" />
        <Skeleton className="h-96 w-full mb-4" />
        <Skeleton className="h-32 w-full" />
      </div>
    );
  }

  if (!item) {
    return (
      <div className="min-h-screen bg-background p-4 flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold mb-2">Item Not Found</h1>
          <p className="text-muted-foreground mb-4">The item you're looking for doesn't exist.</p>
          <Button onClick={() => setLocation("/")}>
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Shop
          </Button>
        </div>
      </div>
    );
  }

  const media = Array.isArray(item.photos) ? item.photos : [];
  const hasMultipleMedia = media.length > 1;
  const currentMedia = media[currentMediaIndex];
  const isVideo = currentMedia?.startsWith("data:video/") || currentMedia?.match(/\.(mp4|webm|ogg|mov)(\?|$)/i);

  const nextMedia = () => {
    setCurrentMediaIndex((prev) => (prev + 1) % media.length);
  };

  const prevMedia = () => {
    setCurrentMediaIndex((prev) => (prev - 1 + media.length) % media.length);
  };

  const handleContactSeller = () => {
    toast({
      title: "Contact Seller",
      description: "Contact functionality coming soon! You'll be able to message the seller directly.",
    });
  };

  const handleMakeOffer = () => {
    toast({
      title: "Make an Offer",
      description: "Payment integration coming soon! You'll be able to purchase items directly.",
    });
  };

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <div className="sticky top-0 z-10 bg-background border-b p-4 flex items-center gap-4">
        <Button
          variant="ghost"
          size="icon"
          onClick={() => setLocation("/")}
          data-testid="button-back"
        >
          <ArrowLeft className="h-5 w-5" />
        </Button>
        <h1 className="text-lg font-semibold flex-1 truncate" data-testid="text-page-title">
          {item.title}
        </h1>
      </div>

      <div className="p-4 space-y-4">
        {/* Media Gallery */}
        {media.length > 0 && (
          <Card className="overflow-hidden">
            <CardContent className="p-0">
              <div className="relative bg-muted min-h-[300px] max-h-[500px] flex items-center justify-center">
                {isVideo ? (
                  <video
                    src={currentMedia}
                    controls
                    playsInline
                    className="w-full h-full object-contain"
                    data-testid={`video-detail-${item.id}`}
                  />
                ) : (
                  <Dialog open={isZoomOpen} onOpenChange={setIsZoomOpen}>
                    <DialogTrigger asChild>
                      <img
                        src={currentMedia}
                        alt={item.title}
                        className="w-full max-h-[500px] object-contain cursor-zoom-in"
                        data-testid={`img-detail-${item.id}`}
                      />
                    </DialogTrigger>
                    <DialogContent className="max-w-[95vw] max-h-[95vh] p-2">
                      <div className="relative w-full h-full flex items-center justify-center">
                        <img
                          src={currentMedia}
                          alt={item.title}
                          className="max-w-full max-h-[90vh] object-contain"
                          data-testid="img-zoomed"
                        />
                        <Button
                          variant="ghost"
                          size="icon"
                          className="absolute top-2 right-2"
                          onClick={() => setIsZoomOpen(false)}
                        >
                          <X className="h-5 w-5" />
                        </Button>
                      </div>
                    </DialogContent>
                  </Dialog>
                )}

                {/* Navigation for multiple media */}
                {hasMultipleMedia && (
                  <>
                    <button
                      onClick={prevMedia}
                      className="absolute left-2 top-1/2 -translate-y-1/2 bg-black/50 text-white p-2 rounded-full hover:bg-black/70"
                      data-testid="button-prev-media"
                    >
                      <ChevronLeft className="h-6 w-6" />
                    </button>
                    <button
                      onClick={nextMedia}
                      className="absolute right-2 top-1/2 -translate-y-1/2 bg-black/50 text-white p-2 rounded-full hover:bg-black/70"
                      data-testid="button-next-media"
                    >
                      <ChevronRight className="h-6 w-6" />
                    </button>

                    {/* Media counter and indicators */}
                    <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-black/50 text-white px-3 py-1 rounded-full text-sm">
                      {currentMediaIndex + 1} / {media.length}
                    </div>

                    {/* Thumbnail strip */}
                    <div className="absolute bottom-16 left-1/2 -translate-x-1/2 flex gap-2 max-w-full overflow-x-auto px-4">
                      {media.map((mediaUrl, index) => {
                        const isThumbVideo = mediaUrl.startsWith("data:video/") || mediaUrl.match(/\.(mp4|webm|ogg|mov)(\?|$)/i);
                        return (
                          <button
                            key={index}
                            onClick={() => setCurrentMediaIndex(index)}
                            className={`flex-shrink-0 h-12 w-12 rounded overflow-hidden border-2 ${
                              index === currentMediaIndex ? "border-white" : "border-white/30"
                            }`}
                            data-testid={`button-thumb-${index}`}
                          >
                            {isThumbVideo ? (
                              <div className="w-full h-full bg-black/80 flex items-center justify-center text-white text-xs">
                                📹
                              </div>
                            ) : (
                              <img
                                src={mediaUrl}
                                alt={`Thumbnail ${index + 1}`}
                                className="w-full h-full object-cover"
                              />
                            )}
                          </button>
                        );
                      })}
                    </div>
                  </>
                )}
              </div>
            </CardContent>
          </Card>
        )}

        {/* Price and Status */}
        <Card>
          <CardContent className="p-4">
            <div className="flex items-start justify-between mb-4">
              <div>
                <h2 className="text-3xl font-bold text-primary mb-1" data-testid="text-price">
                  ${item.price}
                </h2>
                <div className="flex gap-2 items-center">
                  {item.category && (
                    <Badge variant="secondary" data-testid="badge-category">
                      {item.category}
                    </Badge>
                  )}
                  {item.status !== "active" && (
                    <Badge variant="outline" data-testid="badge-status">
                      {item.status}
                    </Badge>
                  )}
                </div>
              </div>
              <div className="flex items-center gap-1 text-muted-foreground">
                <Eye className="h-4 w-4" />
                <span className="text-sm" data-testid="text-views">{item.views || 0}</span>
              </div>
            </div>

            {/* Phone Number */}
            {item.phoneNumber && (
              <div className="mb-4 p-3 bg-muted rounded-lg">
                <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
                  <Phone className="h-4 w-4" />
                  <span>Contact Seller</span>
                </div>
                <a 
                  href={`tel:${item.phoneNumber}`}
                  className="text-lg font-semibold text-primary hover:underline"
                  data-testid="link-phone-number"
                >
                  {item.phoneNumber}
                </a>
              </div>
            )}

            {/* Action Buttons */}
            <div className="grid grid-cols-2 gap-2 mb-4">
              <Button
                size="lg"
                className="w-full"
                onClick={handleMakeOffer}
                data-testid="button-make-offer"
              >
                <DollarSign className="h-5 w-5 mr-2" />
                Buy Now
              </Button>
              <Button
                size="lg"
                variant="outline"
                className="w-full"
                onClick={handleContactSeller}
                data-testid="button-contact-seller"
              >
                <MessageCircle className="h-5 w-5 mr-2" />
                Contact
              </Button>
            </div>

            {/* Item Management Buttons (Creator & Admin Only) */}
            {canManageItem && (
              <div className="space-y-2 pt-4 border-t">
                <div className="grid grid-cols-2 gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    className="w-full"
                    onClick={startEdit}
                  >
                    <Pencil className="h-4 w-4 mr-2" />
                    Edit Item
                  </Button>
                  {item.status !== "sold" && (
                    <Button
                      variant="outline"
                      size="sm"
                      className="w-full"
                      onClick={() => markAsSoldMutation.mutate()}
                      disabled={markAsSoldMutation.isPending}
                      data-testid="button-mark-as-sold"
                    >
                      <CheckCircle2 className="h-4 w-4 mr-2" />
                      Mark as Sold
                    </Button>
                  )}
                </div>
                <Button
                  variant="destructive"
                  size="sm"
                  className="w-full"
                  onClick={() => setDeleteConfirmOpen(true)}
                  disabled={deleteMutation.isPending}
                  data-testid="button-delete-item"
                >
                  <Trash2 className="h-4 w-4 mr-2" />
                  Delete Item
                </Button>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Description */}
        <Card>
          <CardContent className="p-4">
            <h3 className="text-lg font-semibold mb-2">Description</h3>
            <p className="text-foreground whitespace-pre-wrap" data-testid="text-full-description">
              {item.description}
            </p>
          </CardContent>
        </Card>

        {/* Payment Options Info */}
        <Card>
          <CardContent className="p-4">
            <h3 className="text-lg font-semibold mb-2">Payment Options</h3>
            <div className="space-y-2 text-sm text-muted-foreground">
              <p>💳 Cash on delivery</p>
              <p>💵 Bank transfer</p>
              <p>🪙 Cryptocurrency (coming soon)</p>
              <p className="pt-2 border-t">
                <strong>Safe Transaction Tips:</strong> Meet in public places, inspect items before payment,
                and use secure payment methods.
              </p>
            </div>
          </CardContent>
        </Card>

        {/* Item Details */}
        <Card>
          <CardContent className="p-4">
            <h3 className="text-lg font-semibold mb-2">Item Details</h3>
            <div className="space-y-1 text-sm">
              <div className="flex justify-between">
                <span className="text-muted-foreground">Posted</span>
                <span>{new Date(item.createdAt).toLocaleDateString()}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">Item ID</span>
                <span className="font-mono text-xs">{item.id.slice(0, 8)}...</span>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Edit Dialog */}
      <Dialog open={isEditOpen} onOpenChange={setIsEditOpen}>
        <DialogContent className="max-w-md max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Edit Item</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label>Title</Label>
              <Input value={editTitle} onChange={(e) => setEditTitle(e.target.value)} />
            </div>
            <div>
              <Label>Price</Label>
              <Input value={editPrice} onChange={(e) => setEditPrice(e.target.value)} placeholder="0.00" />
            </div>
            <div>
              <Label>Category</Label>
              <Input value={editCategory} onChange={(e) => setEditCategory(e.target.value)} placeholder="Optional category" />
            </div>
            <div>
              <Label>Description</Label>
              <Textarea value={editDescription} onChange={(e) => setEditDescription(e.target.value)} rows={4} />
            </div>
            <Button onClick={handleUpdate} disabled={updateMutation.isPending} className="w-full">
              {updateMutation.isPending ? "Saving..." : "Save Changes"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <AlertDialog open={deleteConfirmOpen} onOpenChange={setDeleteConfirmOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Shop Item?</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete this item? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel data-testid="button-cancel-delete">Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => {
                deleteMutation.mutate();
                setDeleteConfirmOpen(false);
              }}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              data-testid="button-confirm-delete"
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

client/src/components/ui/radio-group.tsx.content:
import * as React from "react"
import * as RadioGroupPrimitive from "@radix-ui/react-radio-group"
import { Circle } from "lucide-react"

import { cn } from "@/lib/utils"

