    const totalRewardsPaid = parseFloat(totalRewardsResult[0]?.totalPaid || '0');

    // Get top referrers (users with most successful referrals)
    const topReferrers = await db
      .select({
        userId: users.id,
        email: users.email,
        firstName: users.firstName,
        lastName: users.lastName,
