                        <td className="py-2 px-3">
                          <Badge className={wallet.userRole === 'employee' ? 'bg-orange-500/20 text-orange-300' : wallet.userRole === 'customer' ? 'bg-blue-500/20 text-blue-300' : 'bg-purple-500/20 text-purple-300'}>
                            {wallet.userRole}
                          </Badge>
                        </td>
                        <td className="py-2 px-3 text-right font-bold text-green-400">{parseFloat(wallet.tokenBalance).toFixed(2)}</td>
                        <td className="py-2 px-3 text-right text-slate-300">{parseFloat(wallet.totalEarned).toFixed(2)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              {(!tokenLedger?.wallets || tokenLedger.wallets.length === 0) && (
                <div className="text-center py-8 text-slate-400">
                  No wallet accounts yet
                </div>
              )}
            </Card>
          </TabsContent>

          {/* Reward Configuration Tab */}
          <TabsContent value="reward-config" className="space-y-6">
            <Card className="p-6 border border-slate-700/50 bg-gradient-to-br from-slate-800/80 to-slate-900/80">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                  <div className="p-3 rounded-xl bg-gradient-to-br from-teal-500 to-cyan-600">
                    <Settings className="h-6 w-6 text-white" />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold text-white">Reward Configuration</h2>
                    <p className="text-sm text-slate-400">Configure token amounts for customer and employee rewards</p>
                  </div>
                </div>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => refetchRewardSettings()}
                  className="border-teal-500/50 text-teal-300 hover:bg-teal-500/10"
                  data-testid="button-refresh-rewards"
                >
                  <RefreshCw className="h-4 w-4 mr-2" />
                  Refresh
                </Button>
              </div>

              <div className="space-y-4">
                {rewardSettings?.map((setting) => (
                  <div key={setting.id} className="flex items-center justify-between p-4 rounded-lg bg-slate-900/50 border border-slate-700/50">
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <span className="text-white font-medium">{setting.label}</span>
                        <Badge variant="outline" className={setting.isActive ? "border-green-500 text-green-400" : "border-red-500 text-red-400"}>
                          {setting.isActive ? "Active" : "Inactive"}
                        </Badge>
                      </div>
                      {setting.description && (
                        <p className="text-sm text-slate-400 mt-1">{setting.description}</p>
                      )}
                      <div className="text-xs text-slate-500 mt-1">
                        Key: {setting.settingKey}
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      {editingRewardKey === setting.settingKey ? (
                        <>
                          <Input
                            type="number"
                            value={newRewardAmount}
                            onChange={(e) => setNewRewardAmount(e.target.value)}
                            className="w-32 bg-slate-800 border-slate-600"
                            placeholder="Amount"
                            data-testid={`input-reward-${setting.settingKey}`}
                          />
                          <Button
                            size="sm"
                            onClick={() => {
                              const amount = parseFloat(newRewardAmount);
                              if (!isNaN(amount) && amount >= 0) {
                                updateRewardSettingMutation.mutate({ key: setting.settingKey, tokenAmount: amount });
                              }
                            }}
                            disabled={updateRewardSettingMutation.isPending}
                            className="bg-green-600 hover:bg-green-700"
                            data-testid={`button-save-reward-${setting.settingKey}`}
                          >
                            {updateRewardSettingMutation.isPending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                          </Button>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => {
                              setEditingRewardKey(null);
                              setNewRewardAmount("");
                            }}
                            className="border-slate-600"
                            data-testid={`button-cancel-reward-${setting.settingKey}`}
                          >
                            <XCircle className="h-4 w-4" />
                          </Button>
                        </>
                      ) : (
                        <>
                          <div className="text-right">
                            <div className="text-2xl font-bold text-teal-400">
                              {parseFloat(setting.tokenAmount).toLocaleString()}
                            </div>
                            <div className="text-xs text-slate-500">
                              ${(parseFloat(setting.tokenAmount) * 0.01).toFixed(2)} value
                            </div>
                          </div>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => {
                              setEditingRewardKey(setting.settingKey);
                              setNewRewardAmount(setting.tokenAmount);
                            }}
                            className="border-teal-500/50 text-teal-300 hover:bg-teal-500/10"
                            data-testid={`button-edit-reward-${setting.settingKey}`}
                          >
                            <Edit className="h-4 w-4" />
                          </Button>
                        </>
                      )}
                    </div>
                  </div>
                ))}

                {(!rewardSettings || rewardSettings.length === 0) && (
                  <div className="text-center py-8 text-slate-400">
                    <Settings className="h-12 w-12 mx-auto mb-4 opacity-50" />
                    No reward settings configured
                  </div>
                )}
              </div>

              <div className="mt-6 p-4 rounded-lg bg-teal-500/10 border border-teal-500/30">
                <h4 className="font-medium text-teal-300 mb-2">Reward Value Guide (1 JCMOVES = $0.01)</h4>
                <ul className="text-sm text-slate-400 space-y-1">
                  <li>• <strong>200 JCMOVES</strong> = $2.00 (Quote Accepted)</li>
                  <li>• <strong>1,500 JCMOVES</strong> = $15.00 (Job Completed)</li>
                  <li>• <strong>2,500 JCMOVES</strong> = $25.00 (Referral Confirmed)</li>
                </ul>
              </div>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </div>
  );
}

client/src/pages/employee-dashboard.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { 
  Award, 
  TrendingUp, 
  Calendar, 
  Coins, 
  Target, 
  Zap,
  Flame,
  Trophy,
  Settings,
  Eye,
  EyeOff
} from "lucide-react";
import { Link } from "wouter";
import { useState } from "react";
import { format } from "date-fns";
import { EmployeeReviews } from "@/components/employee-reviews";

interface GamificationStats {
  points: number;
  level: number;
  nextLevelPoints: number;
  currentLevelPoints: number;
  totalTokensEarned: string;
  streakCount: number;
  lastCheckInDate: string | null;
  achievements: any[];
  weeklyPoints: number;
  weeklyRank: number | null;
}

interface WalletData {
  tokenBalance: string;
  cashValue: string;
  pendingTokens: string;
  totalEarned: string;
}

interface Lead {
  id: string;
  firstName: string;
  lastName: string;
  serviceType: string;
  status: string;
  confirmedDate?: string;
  confirmedFromAddress?: string;
  confirmedToAddress?: string;
  tokenAllocation?: string;
  basePrice?: string;
  crewMembers?: string[];
}

export default function EmployeeDashboard() {
  const [dashboardSettings, setDashboardSettings] = useState({
    showBalance: true,
    showUpcomingJobs: true,
    showPerformance: true,
    showStreaks: true,
    showReviews: true,
  });

  // Get current user
  const { data: user } = useQuery<{ id: string; email: string; role: string }>({
    queryKey: ["/api/auth/user"],
  });

  const { data: gamificationStats, isLoading: statsLoading } = useQuery<GamificationStats>({
    queryKey: ["/api/gamification/stats"],
  });

  const { data: walletData, isLoading: walletLoading } = useQuery<WalletData>({
    queryKey: ["/api/rewards/wallet"],
  });

  const { data: myJobs = [], isLoading: jobsLoading } = useQuery<Lead[]>({
    queryKey: ["/api/leads/my-jobs"],
  });

  // Filter upcoming jobs (confirmed but not completed)
  const upcomingJobs = myJobs.filter(
    job => job.status !== 'completed' && job.confirmedDate
  ).sort((a, b) => {
    if (!a.confirmedDate || !b.confirmedDate) return 0;
    return new Date(a.confirmedDate).getTime() - new Date(b.confirmedDate).getTime();
  });

  const toggleSetting = (key: keyof typeof dashboardSettings) => {
    setDashboardSettings(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const tokenBalance = parseFloat(walletData?.tokenBalance || "0");
  const totalEarned = parseFloat(walletData?.totalEarned || "0");
  const pendingTokens = parseFloat(walletData?.pendingTokens || "0");

  return (
    <div className="min-h-screen bg-gradient-to-b from-slate-900 via-slate-800 to-slate-900 p-4 md:p-8">
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl md:text-4xl font-bold text-white" data-testid="text-dashboard-title">
              My Dashboard
            </h1>
            <p className="text-slate-400 mt-1">
              Track your performance and upcoming work
            </p>
          </div>
          <Link href="/employee">
            <Button variant="ghost" className="text-white/70 hover:text-white hover:bg-white/10" data-testid="button-back-home">
              <Calendar className="h-4 w-4 mr-2" />
              Calendar View
            </Button>
          </Link>
        </div>

        {/* Dashboard Settings Toggle */}
        <Card className="bg-slate-800/50 border-slate-700" data-testid="card-dashboard-settings">
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2 text-white">
              <Settings className="h-5 w-5" />
              Customize Dashboard
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex flex-wrap gap-2">
              <Button
                variant={dashboardSettings.showBalance ? "default" : "outline"}
                size="sm"
                onClick={() => toggleSetting('showBalance')}
                data-testid="toggle-balance"
              >
                {dashboardSettings.showBalance ? <Eye className="h-4 w-4 mr-1" /> : <EyeOff className="h-4 w-4 mr-1" />}
                Token Balance
              </Button>
              <Button
                variant={dashboardSettings.showUpcomingJobs ? "default" : "outline"}
                size="sm"
                onClick={() => toggleSetting('showUpcomingJobs')}
                data-testid="toggle-jobs"
              >
                {dashboardSettings.showUpcomingJobs ? <Eye className="h-4 w-4 mr-1" /> : <EyeOff className="h-4 w-4 mr-1" />}
                Upcoming Jobs
              </Button>
              <Button
                variant={dashboardSettings.showPerformance ? "default" : "outline"}
                size="sm"
                onClick={() => toggleSetting('showPerformance')}
                data-testid="toggle-performance"
              >
                {dashboardSettings.showPerformance ? <Eye className="h-4 w-4 mr-1" /> : <EyeOff className="h-4 w-4 mr-1" />}
                Performance
              </Button>
              <Button
                variant={dashboardSettings.showStreaks ? "default" : "outline"}
                size="sm"
                onClick={() => toggleSetting('showStreaks')}
                data-testid="toggle-streaks"
              >
                {dashboardSettings.showStreaks ? <Eye className="h-4 w-4 mr-1" /> : <EyeOff className="h-4 w-4 mr-1" />}
                Streaks & Level
              </Button>
              <Button
                variant={dashboardSettings.showReviews ? "default" : "outline"}
                size="sm"
                onClick={() => toggleSetting('showReviews')}
                data-testid="toggle-reviews"
              >
                {dashboardSettings.showReviews ? <Eye className="h-4 w-4 mr-1" /> : <EyeOff className="h-4 w-4 mr-1" />}
                Customer Reviews
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Token Balance Section */}
        {dashboardSettings.showBalance && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <Card className="bg-gradient-to-br from-blue-500 to-blue-600 text-white" data-testid="card-token-balance">
              <CardHeader>
                <CardTitle className="flex items-center gap-2 text-white">
                  <Coins className="h-5 w-5" />
                  Token Balance
                </CardTitle>
              </CardHeader>
              <CardContent>
                {walletLoading ? (
                  <Skeleton className="h-12 w-full bg-white/20" />
                ) : (
                  <div>
                    <p className="text-4xl font-bold" data-testid="text-token-balance">
                      {tokenBalance.toFixed(2)}
                    </p>
                    <p className="text-blue-100 text-sm mt-1">JCMOVES Tokens</p>
                  </div>
                )}
              </CardContent>
            </Card>

            <Card className="bg-gradient-to-br from-green-500 to-green-600 text-white" data-testid="card-total-earned">
              <CardHeader>
                <CardTitle className="flex items-center gap-2 text-white">
                  <TrendingUp className="h-5 w-5" />
                  Total Earned
                </CardTitle>
              </CardHeader>
              <CardContent>
                {walletLoading ? (
                  <Skeleton className="h-12 w-full bg-white/20" />
                ) : (
                  <div>
                    <p className="text-4xl font-bold" data-testid="text-total-earned">
                      {totalEarned.toFixed(2)}
                    </p>
                    <p className="text-green-100 text-sm mt-1">All-Time Tokens</p>
                  </div>
                )}
              </CardContent>
            </Card>

            <Card className="bg-gradient-to-br from-purple-500 to-purple-600 text-white" data-testid="card-pending-tokens">
              <CardHeader>
                <CardTitle className="flex items-center gap-2 text-white">
                  <Zap className="h-5 w-5" />
                  Pending
                </CardTitle>
              </CardHeader>
              <CardContent>
                {walletLoading ? (
                  <Skeleton className="h-12 w-full bg-white/20" />
                ) : (
                  <div>
                    <p className="text-4xl font-bold" data-testid="text-pending-tokens">
                      {pendingTokens.toFixed(2)}
                    </p>
                    <p className="text-purple-100 text-sm mt-1">Awaiting Transfer</p>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        )}

        {/* Performance Metrics */}
        {dashboardSettings.showPerformance && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <Card data-testid="card-jobs-completed">
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Jobs Completed
                </CardTitle>
              </CardHeader>
              <CardContent>
                {statsLoading ? (
                  <Skeleton className="h-10 w-20" />
                ) : (
                  <div className="flex items-center gap-2">
                    <Target className="h-8 w-8 text-blue-500" />
                    <p className="text-3xl font-bold" data-testid="text-jobs-completed">
                      {myJobs.filter(j => j.status === 'completed').length}
                    </p>
                  </div>
                )}
              </CardContent>
            </Card>

            <Card data-testid="card-weekly-points">
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Weekly Points
                </CardTitle>
              </CardHeader>
              <CardContent>
                {statsLoading ? (
                  <Skeleton className="h-10 w-20" />
                ) : (
                  <div className="flex items-center gap-2">
                    <Trophy className="h-8 w-8 text-yellow-500" />
                    <p className="text-3xl font-bold" data-testid="text-weekly-points">
                      {gamificationStats?.weeklyPoints || 0}
                    </p>
                  </div>
                )}
              </CardContent>
            </Card>

            <Card data-testid="card-weekly-rank">
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Weekly Rank
                </CardTitle>
              </CardHeader>
              <CardContent>
                {statsLoading ? (
                  <Skeleton className="h-10 w-20" />
                ) : (
                  <div className="flex items-center gap-2">
                    <Award className="h-8 w-8 text-purple-500" />
                    <p className="text-3xl font-bold" data-testid="text-weekly-rank">
                      {gamificationStats?.weeklyRank ? `#${gamificationStats.weeklyRank}` : 'N/A'}
                    </p>
                  </div>
                )}
              </CardContent>
            </Card>

            <Card data-testid="card-upcoming-jobs-count">
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Upcoming Jobs
                </CardTitle>
              </CardHeader>
              <CardContent>
                {jobsLoading ? (
                  <Skeleton className="h-10 w-20" />
                ) : (
                  <div className="flex items-center gap-2">
                    <Calendar className="h-8 w-8 text-green-500" />
                    <p className="text-3xl font-bold" data-testid="text-upcoming-jobs-count">
                      {upcomingJobs.length}
                    </p>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        )}

        {/* Streaks and Level */}
        {dashboardSettings.showStreaks && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Card data-testid="card-level-progress">
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Award className="h-5 w-5 text-yellow-500" />
                  Level Progress
                </CardTitle>
                <CardDescription>
                  Keep earning points to level up!
                </CardDescription>
              </CardHeader>
              <CardContent>
                {statsLoading ? (
                  <div className="space-y-2">
                    <Skeleton className="h-4 w-full" />
                    <Skeleton className="h-8 w-24" />
                  </div>
                ) : (
                  <div>
                    <div className="flex items-center justify-between mb-2">
                      <span className="text-sm text-muted-foreground">Level {gamificationStats?.level || 1}</span>
                      <span className="text-sm font-medium">
                        {gamificationStats?.points || 0} / {gamificationStats?.nextLevelPoints || 100} pts
                      </span>
                    </div>
                    <div className="w-full bg-slate-200 dark:bg-slate-700 rounded-full h-3">
                      <div
                        className="bg-gradient-to-r from-yellow-400 to-yellow-600 h-3 rounded-full transition-all duration-500"
                        style={{
                          width: `${Math.min(
                            100,
                            ((gamificationStats?.points || 0) / (gamificationStats?.nextLevelPoints || 100)) * 100
                          )}%`,
                        }}
                        data-testid="progress-level"
                      />
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>

            <Card data-testid="card-streak">
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Flame className="h-5 w-5 text-orange-500" />
                  Daily Streak
                </CardTitle>
                <CardDescription>
                  Check in daily to maintain your streak
                </CardDescription>
              </CardHeader>
              <CardContent>
                {statsLoading ? (
                  <Skeleton className="h-16 w-32" />
                ) : (
                  <div className="flex items-center gap-4">
                    <div className="text-5xl">🔥</div>
                    <div>
                      <p className="text-4xl font-bold" data-testid="text-streak-count">
                        {gamificationStats?.streakCount || 0}
                      </p>
                      <p className="text-sm text-muted-foreground">days in a row</p>
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        )}

        {/* Customer Reviews */}
        {dashboardSettings.showReviews && user?.id && (
          <EmployeeReviews employeeId={user.id} limit={5} showStats={true} />
        )}

        {/* Upcoming Jobs List */}
        {dashboardSettings.showUpcomingJobs && (
          <Card data-testid="card-upcoming-jobs-list">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Calendar className="h-5 w-5" />
                Upcoming Jobs
              </CardTitle>
              <CardDescription>
                Your scheduled jobs for the coming days
              </CardDescription>
            </CardHeader>
            <CardContent>
              {jobsLoading ? (
                <div className="space-y-3">
                  {[1, 2, 3].map((i) => (
                    <Skeleton key={i} className="h-24 w-full" />
                  ))}
                </div>
              ) : upcomingJobs.length === 0 ? (
                <div className="text-center py-12">
                  <Calendar className="h-12 w-12 text-muted-foreground mx-auto mb-3" />
                  <p className="text-muted-foreground">No upcoming jobs scheduled</p>
                  <p className="text-sm text-muted-foreground mt-1">
                    Check the calendar for available jobs to accept
                  </p>
                </div>
              ) : (
                <div className="space-y-3">
                  {upcomingJobs.map((job) => (
                    <div
                      key={job.id}
                      className="p-4 border border-border rounded-lg hover:bg-accent transition-colors"
                      data-testid={`job-item-${job.id}`}
                    >
                      <div className="flex items-start justify-between">
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-1">
                            <h4 className="font-semibold">
                              {job.firstName} {job.lastName}
                            </h4>
                            <Badge variant="outline" data-testid={`badge-service-${job.id}`}>
                              {job.serviceType}
                            </Badge>
                            <Badge data-testid={`badge-status-${job.id}`}>
                              {job.status}
                            </Badge>
                          </div>
                          {job.confirmedDate && (
                            <p className="text-sm text-muted-foreground mb-2">
                              📅 {format(new Date(job.confirmedDate), 'EEEE, MMMM d, yyyy')}
                            </p>
                          )}
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-2 text-sm">
                            {job.confirmedFromAddress && (
                              <p className="text-muted-foreground">
                                <span className="font-medium">From:</span> {job.confirmedFromAddress}
                              </p>
                            )}
                            {job.confirmedToAddress && (
                              <p className="text-muted-foreground">
                                <span className="font-medium">To:</span> {job.confirmedToAddress}
                              </p>
                            )}
                          </div>
                        </div>
                        <div className="text-right ml-4">
                          {job.tokenAllocation && (
                            <div className="mb-2">
                              <p className="text-xs text-muted-foreground">Reward Pool</p>
                              <p className="font-bold text-green-600 dark:text-green-400">
                                {parseFloat(job.tokenAllocation).toFixed(2)} JCMOVES
                              </p>
                            </div>
                          )}
                          {job.basePrice && (
                            <div>
                              <p className="text-xs text-muted-foreground">Base Price</p>
                              <p className="font-semibold">
                                ${parseFloat(job.basePrice).toFixed(2)}
                              </p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        )}
      </div>
    </div>
  );
}

client/src/pages/admin-users.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { useIsMobile } from "@/hooks/use-mobile";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { 
  Users, 
  UserCog, 
  Search, 
  Eye,
  Wallet,
  TrendingUp,
  Award,
  Briefcase,
  Clock,
  Shield,
  ChevronRight,
  Send,
  ArrowRightLeft,
  History
} from "lucide-react";
import { Link } from "wouter";

interface User {
  id: string;
  email: string;
  firstName: string;
  lastName: string;
  username?: string;
  role: string;
  status: 'pending' | 'approved' | 'active' | 'removed';
  createdAt: string;
  referralCount: number;
}

interface UserDetails {
  user: User;
  wallet: {
    tokenBalance: string;
    totalEarnings: string;
  };
  employeeStats: {
    totalPoints: number;
    currentLevel: number;
    totalEarnedTokens: string;
    jobsCompleted: number;
    streakCount: number;
    lastActivityDate: string;
  } | null;
  recentRewards: Array<{
    id: string;
    rewardType: string;
    tokenAmount: string;
    cashValue: string;
    status: string;
    earnedDate: string;
    referenceId?: string;
  }>;
  pendingRequests: {
    cashouts: number;
    cashoutDetails: Array<{
      id: string;
      tokenAmount: string;
      usdValue: string;
      status: string;
      createdAt: string;
    }>;
  };
  jobs: {
    assignedCount: number;
    createdCount: number;
    recentAssigned: Array<{
      id: string;
      serviceType: string;
      status: string;
      createdAt: string;
    }>;
    recentCreated: Array<{
      id: string;
      serviceType: string;
      status: string;
      createdAt: string;
    }>;
  };
}

export default function AdminUsersPage() {
  const { user, hasAdminAccess, isLoading: authLoading } = useAuth();
  const isMobile = useIsMobile();
  const { toast } = useToast();
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedUser, setSelectedUser] = useState<string | null>(null);
  const [detailsTab, setDetailsTab] = useState("overview");
  const [walletModalOpen, setWalletModalOpen] = useState(false);
  const [transferAmount, setTransferAmount] = useState("");
  const [transferDescription, setTransferDescription] = useState("");
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [userToDelete, setUserToDelete] = useState<User | null>(null);

  // Check if user has admin or business_owner role
  const hasAccess = hasAdminAccess || user?.role === 'business_owner';

  // Fetch all users
  const { data: users, isLoading: usersLoading } = useQuery<User[]>({
    queryKey: ["/api/admin/users"],
    enabled: !!hasAccess,
  });

  // Fetch selected user details
  const { data: userDetails, isLoading: detailsLoading } = useQuery<UserDetails>({
    queryKey: ["/api/admin/users", selectedUser, "details"],
    enabled: !!selectedUser,
  });

  // Fetch user wallet transaction history
  const { data: walletHistory, isLoading: historyLoading } = useQuery<{
    success: boolean;
    transactions: Array<{
      id: string;
      type: string;
      tokenAmount: string;
      cashValue: string;
      status: string;
      date: string;
      referenceId?: string;
      metadata?: any;
    }>;
    totalCount: number;
  }>({
    queryKey: ["/api/admin/wallet", selectedUser, "history"],
    enabled: !!selectedUser && walletModalOpen,
  });

  // Transfer tokens mutation
  const transferMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest(
        "POST",
        `/api/admin/wallet/${selectedUser}/transfer`,
        {
          tokenAmount: parseFloat(transferAmount),
          description: transferDescription || "Admin transfer"
        }
      );
      return await response.json();
    },
    onSuccess: (data: any) => {
      toast({
        title: "Transfer Successful",
        description: data.message || "Tokens transferred successfully"
      });
      setTransferAmount("");
      setTransferDescription("");
      // Invalidate queries to refresh data
      queryClient.invalidateQueries({ queryKey: ["/api/admin/users", selectedUser, "details"] });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/wallet", selectedUser, "history"] });
    },
    onError: (error: any) => {
      toast({
        title: "Transfer Failed",
        description: error.message || "Failed to transfer tokens",
        variant: "destructive"
      });
    }
  });

  // Update user status mutation
  const updateStatusMutation = useMutation({
    mutationFn: async ({ userId, status }: { userId: string; status: 'pending' | 'approved' | 'active' | 'removed' }) => {
      const response = await apiRequest(
        "PATCH",
        `/api/admin/users/${userId}/status`,
        { status }
      );
      return await response.json();
    },
    onSuccess: (data: any, variables) => {
      const statusLabels: Record<string, string> = { pending: 'Pending', approved: 'Approved', active: 'Active', removed: 'Removed' };
      toast({
        title: "Status Updated",
        description: `User status changed to ${statusLabels[variables.status]}`
      });
      // Refresh user list
      queryClient.invalidateQueries({ queryKey: ["/api/admin/users"] });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/users", variables.userId, "details"] });
    },
    onError: (error: any) => {
      toast({
        title: "Update Failed",
        description: error.message || "Failed to update user status",
        variant: "destructive"
      });
    }
  });

  // Delete user mutation
  const deleteUserMutation = useMutation({
    mutationFn: async (userId: string) => {
      const response = await apiRequest(
        "DELETE",
        `/api/admin/users/${userId}`
      );
      return await response.json();
    },
    onSuccess: (data: any) => {
      toast({
        title: "User Deleted",
        description: data.message || "User successfully deleted"
      });
      setSelectedUser(null);
      setWalletModalOpen(false);
      setDeleteConfirmOpen(false);
      setUserToDelete(null);
      // Refresh user list
      queryClient.invalidateQueries({ queryKey: ["/api/admin/users"] });
    },
    onError: (error: any) => {
      toast({
        title: "Delete Failed",
        description: error.message || "Failed to delete user",
        variant: "destructive"
      });
    }
  });

  if (authLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto"></div>
          <p className="mt-4 text-muted-foreground">Loading...</p>
        </div>
      </div>
    );
  }

  if (!hasAccess) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <Card>
          <CardHeader>
            <div className="text-center">
              <Shield className="h-12 w-12 text-destructive mx-auto mb-3" />
              <CardTitle className="text-destructive">Access Denied</CardTitle>
              <CardDescription>Administrator privileges required</CardDescription>
            </div>
          </CardHeader>
          <CardContent>
            <Link href="/">
              <Button variant="outline" className="w-full" data-testid="button-back-to-main">
                Back to Main
              </Button>
            </Link>
          </CardContent>
        </Card>
      </div>
    );
  }

  // Filter users based on search
  const filteredUsers = users?.filter(user => {
    const searchLower = searchTerm.toLowerCase();
    return (
      user.firstName?.toLowerCase().includes(searchLower) ||
      user.lastName?.toLowerCase().includes(searchLower) ||
      user.email?.toLowerCase().includes(searchLower) ||
      user.username?.toLowerCase().includes(searchLower)
    );
  }) || [];

  // Separate employees and customers
  const employees = filteredUsers.filter(u => u.role === 'employee' || u.role === 'admin' || u.role === 'business_owner');
  const customers = filteredUsers.filter(u => u.role === 'customer');

  const getRoleBadge = (role: string) => {
    const variants: Record<string, { variant: "default" | "secondary" | "destructive" | "outline", label: string }> = {
      admin: { variant: "destructive", label: "Admin" },
      business_owner: { variant: "destructive", label: "Owner" },
      employee: { variant: "default", label: "Employee" },
      customer: { variant: "secondary", label: "Customer" }
    };
    const config = variants[role] || variants.customer;
    return <Badge variant={config.variant} data-testid={`badge-role-${role}`}>{config.label}</Badge>;
  };

  const getStatusBadge = (status: 'pending' | 'approved' | 'active' | 'removed') => {
    const variants: Record<string, { variant: "default" | "secondary" | "destructive" | "outline", label: string, className?: string }> = {
      pending: { variant: "outline", label: "Pending", className: "border-yellow-500 text-yellow-600 dark:text-yellow-400" },
      approved: { variant: "outline", label: "Approved", className: "border-green-500 text-green-600 dark:text-green-400" },
      active: { variant: "outline", label: "Active", className: "border-green-500 text-green-600 dark:text-green-400" },
      removed: { variant: "outline", label: "Removed", className: "border-red-500 text-red-600 dark:text-red-400" }
    };
    const config = variants[status] || variants.pending;
    return <Badge variant={config.variant} className={config.className} data-testid={`badge-status-${status}`}>{config.label}</Badge>;
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric'
    });
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900">
      <div className="container mx-auto px-4 py-6 md:py-8 max-w-7xl">
      {/* Header */}
      <div className="mb-6 md:mb-8">
        <h1 className="text-2xl md:text-3xl font-bold text-foreground mb-2" data-testid="heading-admin-users">
          User Management
        </h1>
        <p className="text-sm md:text-base text-muted-foreground">
          View and manage all employees and customers
        </p>
      </div>

      {/* Search Bar */}
      <Card className="mb-6">
        <CardContent className="pt-6">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search by name, email, or username..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10"
              data-testid="input-search-users"
            />
          </div>
        </CardContent>
      </Card>

      {/* User Lists */}
      <Tabs defaultValue="employees" className="w-full">
        <TabsList className={`grid w-full ${isMobile ? 'grid-cols-1' : 'grid-cols-2'} mb-6`}>
          <TabsTrigger value="employees" data-testid="tab-employees">
            <UserCog className="h-4 w-4 mr-2" />
            Employees ({employees.length})
          </TabsTrigger>
          <TabsTrigger value="customers" data-testid="tab-customers">
            <Users className="h-4 w-4 mr-2" />
            Customers ({customers.length})
          </TabsTrigger>
        </TabsList>

        <TabsContent value="employees">
          {usersLoading ? (
            <Card>
              <CardContent className="py-12 text-center">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto mb-4"></div>
                <p className="text-muted-foreground">Loading employees...</p>
              </CardContent>
            </Card>
          ) : employees.length === 0 ? (
            <Card>
              <CardContent className="py-12 text-center">
                <UserCog className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                <p className="text-muted-foreground">No employees found</p>
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
              {employees.map(user => (
                <Card 
                  key={user.id} 
                  className="hover:shadow-lg transition-shadow cursor-pointer"
                  onClick={() => setSelectedUser(user.id)}
                  data-testid={`card-user-${user.id}`}
                >
                  <CardHeader className="pb-3">
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <CardTitle className="text-lg mb-1">
                          {user.firstName} {user.lastName}
                        </CardTitle>
                        <CardDescription className="text-sm break-all">
                          {user.email}
                        </CardDescription>
                      </div>
                      <div className="flex flex-col gap-1">
                        {getRoleBadge(user.role)}
                        {getStatusBadge(user.status)}
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-2 text-sm">
                      {user.username && (
                        <div className="flex items-center text-muted-foreground">
                          <span className="font-medium mr-2">@{user.username}</span>
                        </div>
                      )}
                      <div className="flex items-center justify-between">
                        <span className="text-muted-foreground">Joined</span>
                        <span className="font-medium">{formatDate(user.createdAt)}</span>
                      </div>

                      {/* Status Actions */}
                      <div className="flex gap-2 mt-3">
                        {user.status === 'pending' && (
                          <Button 
                              variant="default" 
                              size="sm" 
                              className="flex-1 bg-green-600 hover:bg-green-700"
                              onClick={(e) => {
                                e.stopPropagation();
                                updateStatusMutation.mutate({ userId: user.id, status: 'approved' });
                              }}
                              data-testid={`button-approve-${user.id}`}
                            >
                              Approve
                            </Button>
                          )}
                          {user.status === 'approved' && (
                            <Button 
                              variant="destructive" 
                              size="sm" 
                              className="flex-1"
                              onClick={(e) => {
                                e.stopPropagation();
                                updateStatusMutation.mutate({ userId: user.id, status: 'removed' });
                              }}
                              data-testid={`button-remove-${user.id}`}
                            >
                              Remove Access
                            </Button>
                          )}
                          {user.status === 'removed' && (
                            <Button 
                              variant="default" 
                              size="sm" 
                              className="flex-1 bg-blue-600 hover:bg-blue-700"
                              onClick={(e) => {
                                e.stopPropagation();
                                updateStatusMutation.mutate({ userId: user.id, status: 'approved' });
                              }}
                              data-testid={`button-restore-${user.id}`}
                            >
                              Restore
                            </Button>
                          )}
                          {(user.status === 'pending' || user.status === 'removed') && (
                            <Button 
                              variant="outline" 
                              size="sm" 
                              className="flex-1"
                              onClick={(e) => {
                                e.stopPropagation();
                                setUserToDelete(user);
                                setDeleteConfirmOpen(true);
                              }}
                              data-testid={`button-delete-${user.id}`}
                            >
                              Delete
                            </Button>
                          )}
                        </div>

                      <Button 
                        variant="outline" 
                        size="sm" 
                        className="w-full mt-2"
                        onClick={(e) => {
                          e.stopPropagation();
                          setSelectedUser(user.id);
                        }}
                        data-testid={`button-view-details-${user.id}`}
                      >
                        <Eye className="h-4 w-4 mr-2" />
                        View Details
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </TabsContent>

        <TabsContent value="customers">
          {usersLoading ? (
            <Card>
              <CardContent className="py-12 text-center">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto mb-4"></div>
                <p className="text-muted-foreground">Loading customers...</p>
              </CardContent>
            </Card>
          ) : customers.length === 0 ? (
            <Card>
              <CardContent className="py-12 text-center">
                <Users className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                <p className="text-muted-foreground">No customers found</p>
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
              {customers.map(user => (
                <Card 
                  key={user.id} 
                  className="hover:shadow-lg transition-shadow cursor-pointer"
                  onClick={() => setSelectedUser(user.id)}
                  data-testid={`card-user-${user.id}`}
                >
                  <CardHeader className="pb-3">
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <CardTitle className="text-lg mb-1">
                          {user.firstName} {user.lastName}
                        </CardTitle>
                        <CardDescription className="text-sm break-all">
                          {user.email}
                        </CardDescription>
                      </div>
                      <div className="flex flex-col gap-1">
                        {getRoleBadge(user.role)}
                        {getStatusBadge(user.status)}
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-2 text-sm">
                      {user.username && (
                        <div className="flex items-center text-muted-foreground">
                          <span className="font-medium mr-2">@{user.username}</span>
                        </div>
                      )}
                      <div className="flex items-center justify-between">
                        <span className="text-muted-foreground">Joined</span>
                        <span className="font-medium">{formatDate(user.createdAt)}</span>
                      </div>
                      <div className="flex items-center justify-between">
                        <span className="text-muted-foreground">Referrals</span>
                        <Badge variant="outline">{user.referralCount || 0}</Badge>
                      </div>

                      {/* Status Actions */}
                      <div className="flex gap-2 mt-3">
                        {user.status === 'pending' && (
                          <Button 
                            variant="default" 
                            size="sm" 
                            className="flex-1 bg-green-600 hover:bg-green-700"
                            onClick={(e) => {
                              e.stopPropagation();
                              updateStatusMutation.mutate({ userId: user.id, status: 'approved' });
                            }}
                            data-testid={`button-approve-${user.id}`}
                          >
                            Approve
                          </Button>
                        )}
                        {user.status === 'approved' && (
                          <Button 
                            variant="destructive" 
                            size="sm" 
                            className="flex-1"
                            onClick={(e) => {
                              e.stopPropagation();
                              updateStatusMutation.mutate({ userId: user.id, status: 'removed' });
                            }}
                            data-testid={`button-remove-${user.id}`}
                          >
                            Remove Access
                          </Button>
                        )}
                        {user.status === 'removed' && (
                          <Button 
                            variant="default" 
                            size="sm" 
                            className="flex-1 bg-blue-600 hover:bg-blue-700"
                            onClick={(e) => {
                              e.stopPropagation();
                              updateStatusMutation.mutate({ userId: user.id, status: 'approved' });
                            }}
                            data-testid={`button-restore-${user.id}`}
                          >
                            Restore
                          </Button>
                        )}
                        {(user.status === 'pending' || user.status === 'removed') && (
                          <Button 
                            variant="outline" 
                            size="sm" 
                            className="flex-1"
                            onClick={(e) => {
                              e.stopPropagation();
                              setUserToDelete(user);
                              setDeleteConfirmOpen(true);
                            }}
                            data-testid={`button-delete-${user.id}`}
                          >
                            Delete
                          </Button>
                        )}
                      </div>

                      <Button 
                        variant="outline" 
                        size="sm" 
                        className="w-full mt-2"
                        onClick={(e) => {
                          e.stopPropagation();
                          setSelectedUser(user.id);
                        }}
                        data-testid={`button-view-details-${user.id}`}
                      >
                        <Eye className="h-4 w-4 mr-2" />
                        View Details
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </TabsContent>
      </Tabs>

      {/* User Details Modal */}
      <Dialog open={!!selectedUser} onOpenChange={(open) => !open && setSelectedUser(null)}>
        <DialogContent className={`${isMobile ? 'max-w-[95vw] h-[90vh]' : 'max-w-3xl max-h-[85vh]'} overflow-hidden flex flex-col`}>
          {detailsLoading ? (
            <div className="flex items-center justify-center py-12">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
            </div>
          ) : !userDetails ? (
            <div className="flex flex-col items-center justify-center py-12">
              <Users className="h-12 w-12 text-muted-foreground mb-4" />
              <p className="text-muted-foreground">Unable to load user details</p>
              <Button variant="outline" className="mt-4" onClick={() => setSelectedUser(null)}>
                Close
              </Button>
            </div>
          ) : (
            <>
              <DialogHeader>
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <DialogTitle className="text-xl md:text-2xl" data-testid="heading-user-details">
                      {userDetails.user.firstName} {userDetails.user.lastName}
                    </DialogTitle>
                    <DialogDescription className="mt-1">
                      {userDetails.user.email}
                    </DialogDescription>
                  </div>
                  <div className="flex items-center gap-2">
                    {getRoleBadge(userDetails.user.role)}
                    {userDetails.user.role === 'customer' && (
                      <Button
                        variant="destructive"
                        size="sm"
                        onClick={() => {
                          if (window.confirm(`Are you sure you want to delete ${userDetails.user.firstName} ${userDetails.user.lastName}? This action cannot be undone.`)) {
                            deleteUserMutation.mutate(userDetails.user.id);
                          }
                        }}
                        disabled={deleteUserMutation.isPending}
                        data-testid="button-delete-user"
                      >
                        <span className="text-xs">Delete</span>
                      </Button>
                    )}
                  </div>
                </div>
              </DialogHeader>

              <ScrollArea className="flex-1 pr-4">
                <Tabs value={detailsTab} onValueChange={setDetailsTab} className="mt-4">
                  <TabsList className={`grid w-full ${isMobile ? 'grid-cols-2' : 'grid-cols-3'}`}>
                    <TabsTrigger value="overview" data-testid="tab-overview">Overview</TabsTrigger>
                    <TabsTrigger value="rewards" data-testid="tab-rewards">Rewards</TabsTrigger>
                    <TabsTrigger value="jobs" data-testid="tab-jobs">Jobs</TabsTrigger>
                  </TabsList>

                  <TabsContent value="overview" className="space-y-4 mt-4">
                    {/* Wallet Info */}
                    <Card>
                      <CardHeader className="pb-3">
                        <div className="flex items-center justify-between">
                          <CardTitle className="text-base flex items-center">
                            <Wallet className="h-4 w-4 mr-2" />
                            Wallet Balance
                          </CardTitle>
                          <Button 
                            variant="outline" 
                            size="sm"
                            onClick={() => setWalletModalOpen(true)}
                            data-testid="button-manage-wallet"
                          >
                            <ArrowRightLeft className="h-4 w-4 mr-2" />
                            Manage
                          </Button>
                        </div>
                      </CardHeader>
                      <CardContent className="space-y-2">
                        <div 
                          className="flex justify-between items-center cursor-pointer hover:bg-muted p-2 rounded transition-colors"
                          onClick={() => setWalletModalOpen(true)}
                          data-testid="button-view-wallet"
                        >
                          <span className="text-muted-foreground">Token Balance</span>
                          <span className="font-bold" data-testid="text-token-balance">
                            {parseFloat(userDetails.wallet.tokenBalance).toLocaleString()} JCMOVES
                          </span>
                        </div>
                        <Separator />
                        <div className="flex justify-between items-center">
                          <span className="text-muted-foreground">Total Earnings</span>
                          <span className="font-bold text-green-600 dark:text-green-400" data-testid="text-total-earnings">
                            ${parseFloat(userDetails.wallet.totalEarnings).toFixed(2)}
                          </span>
                        </div>
                      </CardContent>
                    </Card>

                    {/* Employee Stats */}
                    {userDetails.employeeStats && (
                      <Card>
                        <CardHeader className="pb-3">
                          <CardTitle className="text-base flex items-center">
                            <Award className="h-4 w-4 mr-2" />
                            Employee Stats
                          </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-2">
                          <div className="grid grid-cols-2 gap-4">
                            <div>
                              <p className="text-sm text-muted-foreground">Level</p>
                              <p className="text-xl font-bold" data-testid="text-level">
                                {userDetails.employeeStats.currentLevel}
                              </p>
                            </div>
                            <div>
                              <p className="text-sm text-muted-foreground">Points</p>
                              <p className="text-xl font-bold" data-testid="text-points">
                                {userDetails.employeeStats.totalPoints.toLocaleString()}
                              </p>
                            </div>
                            <div>
                              <p className="text-sm text-muted-foreground">Jobs Completed</p>
                              <p className="text-xl font-bold" data-testid="text-jobs-completed">
                                {userDetails.employeeStats.jobsCompleted}
                              </p>
                            </div>
                            <div>
                              <p className="text-sm text-muted-foreground">Streak</p>
                              <p className="text-xl font-bold" data-testid="text-streak">
                                {userDetails.employeeStats.streakCount} days
                              </p>
                            </div>
                          </div>
                        </CardContent>
                      </Card>
                    )}

                    {/* Pending Requests */}
                    {userDetails.pendingRequests.cashouts > 0 && (
