                  <TabsContent value="rewards" className="space-y-4 mt-4">
                    <Card>
                      <CardHeader className="pb-3">
                        <CardTitle className="text-base flex items-center">
                          <TrendingUp className="h-4 w-4 mr-2" />
                          Recent Rewards
                        </CardTitle>
                      </CardHeader>
                      <CardContent>
                        {userDetails.recentRewards.length === 0 ? (
                          <p className="text-center text-muted-foreground py-4">No rewards yet</p>
                        ) : (
                          <div className="space-y-2">
                            {userDetails.recentRewards.map(reward => (
                              <div key={reward.id} className="flex justify-between items-start p-3 bg-muted rounded" data-testid={`reward-${reward.id}`}>
                                <div className="flex-1">
                                  <p className="font-medium text-sm capitalize">
                                    {reward.rewardType.replace(/_/g, ' ')}
                                  </p>
                                  <p className="text-xs text-muted-foreground">
                                    {formatDate(reward.earnedDate)}
                                  </p>
                                </div>
                                <div className="text-right">
                                  <p className="font-bold text-sm">
                                    +{parseFloat(reward.tokenAmount).toLocaleString()} JCMOVES
                                  </p>
                                  <p className="text-xs text-green-600 dark:text-green-400">
                                    ${parseFloat(reward.cashValue).toFixed(4)}
                                  </p>
                                  <Badge variant="outline" className="mt-1">{reward.status}</Badge>
                                </div>
                              </div>
                            ))}
                          </div>
                        )}
                      </CardContent>
                    </Card>
                  </TabsContent>

                  <TabsContent value="jobs" className="space-y-4 mt-4">
                    {/* Assigned Jobs */}
                    {userDetails.jobs.assignedCount > 0 && (
                      <Card>
                        <CardHeader className="pb-3">
                          <CardTitle className="text-base flex items-center">
                            <Briefcase className="h-4 w-4 mr-2" />
                            Assigned Jobs ({userDetails.jobs.assignedCount})
                          </CardTitle>
                        </CardHeader>
                        <CardContent>
                          <div className="space-y-2">
                            {userDetails.jobs.recentAssigned.map(job => (
                              <div key={job.id} className="flex justify-between items-center p-2 bg-muted rounded" data-testid={`job-assigned-${job.id}`}>
                                <div>
                                  <p className="font-medium text-sm">{job.serviceType}</p>
                                  <p className="text-xs text-muted-foreground">
                                    {formatDate(job.createdAt)}
                                  </p>
                                </div>
                                <Badge>{job.status}</Badge>
                              </div>
                            ))}
                          </div>
                        </CardContent>
                      </Card>
                    )}

                    {/* Created Jobs */}
                    {userDetails.jobs.createdCount > 0 && (
                      <Card>
                        <CardHeader className="pb-3">
                          <CardTitle className="text-base flex items-center">
                            <ChevronRight className="h-4 w-4 mr-2" />
                            Created Jobs ({userDetails.jobs.createdCount})
                          </CardTitle>
                        </CardHeader>
                        <CardContent>
                          <div className="space-y-2">
                            {userDetails.jobs.recentCreated.map(job => (
                              <div key={job.id} className="flex justify-between items-center p-2 bg-muted rounded" data-testid={`job-created-${job.id}`}>
                                <div>
                                  <p className="font-medium text-sm">{job.serviceType}</p>
                                  <p className="text-xs text-muted-foreground">
                                    {formatDate(job.createdAt)}
                                  </p>
                                </div>
                                <Badge>{job.status}</Badge>
                              </div>
                            ))}
                          </div>
                        </CardContent>
                      </Card>
                    )}

                    {userDetails.jobs.assignedCount === 0 && userDetails.jobs.createdCount === 0 && (
                      <Card>
                        <CardContent className="py-12 text-center">
                          <Briefcase className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                          <p className="text-muted-foreground">No jobs found</p>
                        </CardContent>
                      </Card>
                    )}
                  </TabsContent>
                </Tabs>
              </ScrollArea>
            </>
          )}
        </DialogContent>
      </Dialog>

      {/* Wallet Management Modal */}
      <Dialog open={walletModalOpen} onOpenChange={setWalletModalOpen}>
        <DialogContent className={`${isMobile ? 'max-w-[95vw] h-[90vh]' : 'max-w-2xl max-h-[85vh]'} overflow-hidden flex flex-col`}>
          <DialogHeader>
            <DialogTitle className="flex items-center">
              <Wallet className="h-5 w-5 mr-2" />
              Wallet Management - {userDetails?.user.firstName} {userDetails?.user.lastName}
            </DialogTitle>
            <DialogDescription>
              Transfer tokens, view balance, and transaction history
            </DialogDescription>
          </DialogHeader>

          <ScrollArea className="flex-1 pr-4">
            <Tabs defaultValue="transfer" className="mt-4">
              <TabsList className="grid w-full grid-cols-2">
                <TabsTrigger value="transfer" data-testid="tab-wallet-transfer">
                  <Send className="h-4 w-4 mr-2" />
                  Transfer
                </TabsTrigger>
                <TabsTrigger value="history" data-testid="tab-wallet-history">
                  <History className="h-4 w-4 mr-2" />
                  History
                </TabsTrigger>
              </TabsList>

              <TabsContent value="transfer" className="space-y-4 mt-4">
                {/* Current Balance */}
                <Card>
                  <CardHeader className="pb-3">
                    <CardTitle className="text-base">Current Balance</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="text-center py-4">
                      <p className="text-3xl font-bold text-primary">
                        {userDetails && parseFloat(userDetails.wallet.tokenBalance).toLocaleString()} JCMOVES
                      </p>
                      <p className="text-sm text-muted-foreground mt-1">
                        Total Earnings: ${userDetails && parseFloat(userDetails.wallet.totalEarnings).toFixed(2)}
                      </p>
                    </div>
                  </CardContent>
                </Card>

                {/* Transfer Form */}
                <Card>
                  <CardHeader className="pb-3">
                    <CardTitle className="text-base">Transfer Tokens</CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div className="space-y-2">
                      <Label htmlFor="transfer-amount">Amount (JCMOVES)</Label>
                      <Input
                        id="transfer-amount"
                        type="number"
                        placeholder="0.00"
                        value={transferAmount}
                        onChange={(e) => setTransferAmount(e.target.value)}
                        data-testid="input-transfer-amount"
                        min="0"
                        step="0.01"
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="transfer-description">Description (Optional)</Label>
                      <Input
                        id="transfer-description"
                        placeholder="e.g., Bonus reward, Adjustment, etc."
                        value={transferDescription}
                        onChange={(e) => setTransferDescription(e.target.value)}
                        data-testid="input-transfer-description"
                      />
                    </div>
                    <Button
                      className="w-full"
                      onClick={() => transferMutation.mutate()}
                      disabled={!transferAmount || parseFloat(transferAmount) <= 0 || transferMutation.isPending}
                      data-testid="button-execute-transfer"
                    >
                      {transferMutation.isPending ? (
                        <>
                          <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                          Transferring...
                        </>
                      ) : (
                        <>
                          <Send className="h-4 w-4 mr-2" />
                          Transfer Tokens
                        </>
                      )}
                    </Button>
                  </CardContent>
                </Card>
              </TabsContent>

              <TabsContent value="history" className="space-y-4 mt-4">
                {historyLoading ? (
                  <Card>
                    <CardContent className="py-12 text-center">
                      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto mb-4"></div>
                      <p className="text-muted-foreground">Loading transaction history...</p>
                    </CardContent>
                  </Card>
                ) : walletHistory && walletHistory.transactions.length > 0 ? (
                  <div className="space-y-2">
                    {walletHistory.transactions.map(tx => (
                      <Card key={tx.id}>
                        <CardContent className="py-3">
                          <div className="flex justify-between items-start">
                            <div className="flex-1">
                              <p className="font-medium text-sm capitalize">
                                {tx.type.replace(/_/g, ' ')}
                              </p>
                              <p className="text-xs text-muted-foreground">
                                {new Date(tx.date).toLocaleDateString('en-US', {
                                  month: 'short',
                                  day: 'numeric',
                                  year: 'numeric',
                                  hour: '2-digit',
                                  minute: '2-digit'
                                })}
                              </p>
                              {tx.referenceId && (
                                <p className="text-xs text-muted-foreground mt-1">
                                  Ref: {tx.referenceId.slice(0, 8)}...
                                </p>
                              )}
                            </div>
                            <div className="text-right">
                              <p className="font-bold text-sm">
                                +{parseFloat(tx.tokenAmount).toLocaleString()} JCMOVES
                              </p>
                              <p className="text-xs text-green-600 dark:text-green-400">
                                ${parseFloat(tx.cashValue).toFixed(4)}
                              </p>
                              <Badge variant="outline" className="mt-1">{tx.status}</Badge>
                            </div>
                          </div>
                        </CardContent>
                      </Card>
                    ))}
                  </div>
                ) : (
                  <Card>
                    <CardContent className="py-12 text-center">
                      <History className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                      <p className="text-muted-foreground">No transaction history</p>
                    </CardContent>
                  </Card>
                )}
              </TabsContent>
            </Tabs>
          </ScrollArea>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <AlertDialog open={deleteConfirmOpen} onOpenChange={setDeleteConfirmOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete User Account?</AlertDialogTitle>
            <AlertDialogDescription>
              {userToDelete && (
                <div className="space-y-2">
                  <p>
                    You are about to permanently delete the account for{" "}
                    <span className="font-semibold">{userToDelete.firstName} {userToDelete.lastName}</span>{" "}
                    ({userToDelete.email}).
                  </p>
                  <p className="text-destructive font-medium">
                    This action cannot be undone. All user data, including wallet balances, will be transferred to treasury and the account will be permanently removed.
                  </p>
                </div>
              )}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={() => setUserToDelete(null)} data-testid="button-cancel-delete">
              Cancel
            </AlertDialogCancel>
            <AlertDialogAction
              onClick={() => {
                if (userToDelete) {
                  deleteUserMutation.mutate(userToDelete.id);
                }
              }}
              className="bg-destructive hover:bg-destructive/90"
              data-testid="button-confirm-delete"
            >
              {deleteUserMutation.isPending ? "Deleting..." : "Delete Account"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
      </div>
    </div>
  );
}

client/src/components/star-rating.tsx.content:
import { Star } from "lucide-react";

interface StarRatingProps {
  rating: number;
  onRatingChange?: (rating: number) => void;
  readonly?: boolean;
  size?: "sm" | "md" | "lg";
}

export function StarRating({ rating, onRatingChange, readonly = false, size = "md" }: StarRatingProps) {
  const sizeClasses = {
    sm: "h-4 w-4",
    md: "h-5 w-5",
    lg: "h-6 w-6",
  };

  const handleClick = (index: number) => {
    if (!readonly && onRatingChange) {
      onRatingChange(index + 1);
    }
  };

  return (
    <div className="flex gap-1">
      {[...Array(5)].map((_, index) => (
        <Star
          key={index}
          className={`${sizeClasses[size]} ${
            !readonly ? "cursor-pointer hover:scale-110 transition-transform" : ""
          } ${
            index < rating
              ? "fill-yellow-400 text-yellow-400"
              : "fill-muted text-muted-foreground/30"
          }`}
          onClick={() => handleClick(index)}
          data-testid={`star-${index + 1}`}
        />
      ))}
    </div>
  );
}

client/src/components/employee-reviews.t.content:
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { StarRating } from "@/components/star-rating";
import { Badge } from "@/components/ui/badge";
import { Loader2, TrendingUp, Award, MessageSquare } from "lucide-react";

interface Review {
  id: string;
  leadId: string;
  userId: string;
  employeeId: string;
  rating: number;
  comment: string | null;
  rewardedAt: string | null;
  createdAt: string;
}

interface EmployeeReviewsProps {
  employeeId: string;
  limit?: number;
  showStats?: boolean;
}

export function EmployeeReviews({ employeeId, limit = 10, showStats = true }: EmployeeReviewsProps) {
  const { data: reviews = [], isLoading: reviewsLoading } = useQuery<Review[]>({
    queryKey: ["/api/reviews", { employeeId, limit }],
  });

  const { data: stats, isLoading: statsLoading } = useQuery<{
    averageRating: number;
    totalReviews: number;
    ratingDistribution: Record<string, number>;
  }>({
    queryKey: [`/api/reviews/employee/${employeeId}/stats`],
    enabled: showStats,
  });

  if (reviewsLoading || (showStats && statsLoading)) {
    return (
      <Card>
        <CardContent className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      {/* Statistics Card */}
      {showStats && stats && stats.totalReviews > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <TrendingUp className="h-5 w-5" />
              Review Statistics
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="text-center">
                <div className="text-3xl font-bold text-primary">
                  {stats.averageRating.toFixed(1)}
                </div>
                <div className="flex items-center justify-center mt-1">
                  <StarRating rating={Math.round(stats.averageRating)} readonly size="sm" />
                </div>
                <p className="text-sm text-muted-foreground mt-1">Average Rating</p>
              </div>
              <div className="text-center">
                <div className="text-3xl font-bold text-primary">{stats.totalReviews}</div>
                <p className="text-sm text-muted-foreground mt-1">Total Reviews</p>
              </div>
              <div className="text-center">
                <div className="text-3xl font-bold text-primary">
                  {((stats.ratingDistribution['5'] || 0) / stats.totalReviews * 100).toFixed(0)}%
                </div>
                <p className="text-sm text-muted-foreground mt-1">5-Star Reviews</p>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Reviews List */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <MessageSquare className="h-5 w-5" />
            Customer Feedback
          </CardTitle>
          <CardDescription>
            {reviews.length === 0 ? "No reviews yet" : `Showing ${reviews.length} recent review${reviews.length === 1 ? '' : 's'}`}
          </CardDescription>
        </CardHeader>
        <CardContent>
          {reviews.length === 0 ? (
            <div className="text-center py-8">
              <p className="text-muted-foreground">
                Complete jobs to start receiving customer reviews
              </p>
            </div>
          ) : (
            <div className="space-y-4">
              {reviews.map((review) => (
                <div
                  key={review.id}
                  className="border border-border rounded-lg p-4 space-y-3"
                  data-testid={`review-${review.id}`}
                >
                  <div className="flex items-start justify-between">
                    <div className="flex items-center gap-3">
                      <StarRating rating={review.rating} readonly />
                      <span className="text-sm text-muted-foreground">
                        {new Date(review.createdAt).toLocaleDateString()}
                      </span>
                    </div>
                    {review.rewardedAt && (
                      <Badge variant="secondary" className="bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200">
                        <Award className="h-3 w-3 mr-1" />
                        Bonus Earned
                      </Badge>
                    )}
                  </div>

                  {review.comment && (
                    <p className="text-sm text-foreground leading-relaxed">
                      "{review.comment}"
                    </p>
                  )}

                  {!review.comment && (
                    <p className="text-sm text-muted-foreground italic">
                      No written feedback provided
                    </p>
                  )}
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/review-dialog.tsx.content:
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { StarRating } from "@/components/star-rating";
import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Loader2 } from "lucide-react";

interface ReviewDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  jobId: string;
  jobServiceType: string;
  onReviewSubmitted?: () => void;
}

export function ReviewDialog({ open, onOpenChange, jobId, jobServiceType, onReviewSubmitted }: ReviewDialogProps) {
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState("");
  const { toast } = useToast();

  const submitReviewMutation = useMutation({
    mutationFn: async () => {
      if (rating === 0) {
        throw new Error("Please select a star rating");
      }

      return await apiRequest("/api/reviews", "POST", {
        leadId: jobId,
        rating,
        comment: comment.trim() || null,
      });
    },
    onSuccess: () => {
      toast({
        title: "Review Submitted!",
        description: rating >= 4 
          ? `Thank you for your ${rating}-star review! The employee will receive bonus tokens.` 
          : "Thank you for your feedback. We'll use it to improve our service.",
      });

      // Reset form
      setRating(0);
      setComment("");

      // Close dialog
      onOpenChange(false);

      // Invalidate queries to refresh data
      queryClient.invalidateQueries({ queryKey: ["/api/leads/my-requests"] });
      queryClient.invalidateQueries({ queryKey: ["/api/reviews"] });
      queryClient.invalidateQueries({ queryKey: ["/api/reviews/my-reviews"] });

      if (onReviewSubmitted) {
        onReviewSubmitted();
      }
    },
    onError: (error: any) => {
      toast({
        title: "Failed to Submit Review",
        description: error.message || "Please try again later.",
        variant: "destructive",
      });
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    submitReviewMutation.mutate();
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px]" data-testid="dialog-review">
        <DialogHeader>
          <DialogTitle>Rate Your Experience</DialogTitle>
          <DialogDescription>
            How was your {jobServiceType} service? Your feedback helps us improve and rewards great employees.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6 pt-4">
          <div className="space-y-2">
            <label className="text-sm font-medium">Your Rating</label>
            <div className="flex items-center gap-4">
              <StarRating rating={rating} onRatingChange={setRating} size="lg" />
              {rating > 0 && (
                <span className="text-sm text-muted-foreground">
                  {rating === 5 ? "Excellent!" : rating === 4 ? "Great!" : rating === 3 ? "Good" : rating === 2 ? "Fair" : "Needs Improvement"}
                </span>
              )}
            </div>
            {rating >= 4 && (
              <p className="text-xs text-green-600 dark:text-green-400">
                ⭐ {rating === 5 ? "50" : "25"} bonus tokens will be awarded to the employee!
              </p>
            )}
          </div>

          <div className="space-y-2">
            <label htmlFor="comment" className="text-sm font-medium">
              Additional Comments <span className="text-muted-foreground">(optional)</span>
            </label>
            <Textarea
              id="comment"
              placeholder="Tell us about your experience..."
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              rows={4}
              maxLength={1000}
              data-testid="textarea-comment"
            />
            <p className="text-xs text-muted-foreground text-right">
              {comment.length}/1000 characters
            </p>
          </div>

          <div className="flex gap-3 justify-end">
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
              disabled={submitReviewMutation.isPending}
              data-testid="button-cancel"
            >
              Cancel
            </Button>
            <Button
              type="submit"
              disabled={rating === 0 || submitReviewMutation.isPending}
              data-testid="button-submit-review"
            >
              {submitReviewMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Submit Review
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

