import { Storage, File } from "@google-cloud/storage";
import { Response } from "express";
import { randomUUID } from "crypto";

const REPLIT_SIDECAR_ENDPOINT = "http://127.0.0.1:1106";

// The object storage client is used to interact with the object storage service.
export const objectStorageClient = new Storage({
  credentials: {
    audience: "replit",
    subject_token_type: "access_token",
    token_url: `${REPLIT_SIDECAR_ENDPOINT}/token`,
    type: "external_account",
    credential_source: {
      url: `${REPLIT_SIDECAR_ENDPOINT}/credential`,
      format: {
        type: "json",
        subject_token_field_name: "access_token",
      },
    },
    universe_domain: "googleapis.com",
  },
  projectId: "",
});

export class ObjectNotFoundError extends Error {
  constructor() {
    super("Object not found");
    this.name = "ObjectNotFoundError";
    Object.setPrototypeOf(this, ObjectNotFoundError.prototype);
  }
}

// The object storage service is used to interact with the object storage service.
export class ObjectStorageService {
  constructor() {}

  // Gets the public object search paths.
  getPublicObjectSearchPaths(): Array<string> {
    const pathsStr = process.env.PUBLIC_OBJECT_SEARCH_PATHS || "";
    const paths = Array.from(
      new Set(
        pathsStr
          .split(",")
          .map((path) => path.trim())
          .filter((path) => path.length > 0)
      )
    );
    if (paths.length === 0) {
      throw new Error(
        "PUBLIC_OBJECT_SEARCH_PATHS not set. Create a bucket in 'Object Storage' " +
          "tool and set PUBLIC_OBJECT_SEARCH_PATHS env var (comma-separated paths)."
      );
    }
    return paths;
  }

  // Gets the private object directory.
  getPrivateObjectDir(): string {
    const dir = process.env.PRIVATE_OBJECT_DIR || "";
    if (!dir) {
      throw new Error(
        "PRIVATE_OBJECT_DIR not set. Create a bucket in 'Object Storage' " +
          "tool and set PRIVATE_OBJECT_DIR env var."
      );
    }
    return dir;
  }

  // Search for a public object from the search paths.
  async searchPublicObject(filePath: string): Promise<File | null> {
    for (const searchPath of this.getPublicObjectSearchPaths()) {
      const fullPath = `${searchPath}/${filePath}`;

      // Full path format: /<bucket_name>/<object_name>
      const { bucketName, objectName } = parseObjectPath(fullPath);
      const bucket = objectStorageClient.bucket(bucketName);
      const file = bucket.file(objectName);

      // Check if file exists
      const [exists] = await file.exists();
      if (exists) {
        return file;
      }
    }

    return null;
  }

  // Downloads an object to the response.
  async downloadObject(file: File, res: Response, cacheTtlSec: number = 3600) {
    try {
      // Get file metadata
      const [metadata] = await file.getMetadata();

      // Set appropriate headers
      res.set({
        "Content-Type": metadata.contentType || "application/octet-stream",
        "Content-Length": metadata.size,
        "Cache-Control": `public, max-age=${cacheTtlSec}`,
      });

      // Stream the file to the response
      const stream = file.createReadStream();

      stream.on("error", (err) => {
        console.error("Stream error:", err);
        if (!res.headersSent) {
          res.status(500).json({ error: "Error streaming file" });
        }
      });

      stream.pipe(res);
    } catch (error) {
      console.error("Error downloading file:", error);
      if (!res.headersSent) {
        res.status(500).json({ error: "Error downloading file" });
      }
    }
  }

  // Save a base64-encoded image to object storage and return the public URL
  async saveBase64Image(base64Data: string, fileExtension: string = 'jpg'): Promise<string> {
    // Extract the base64 content (remove data URL prefix if present)
    const base64Match = base64Data.match(/^data:image\/\w+;base64,(.+)$/);
    const base64Content = base64Match ? base64Match[1] : base64Data;

    // Decode base64 to buffer
    const buffer = Buffer.from(base64Content, 'base64');

    // Generate unique filename in the public directory
    const filename = `shop/${randomUUID()}.${fileExtension}`;
    const publicSearchPaths = this.getPublicObjectSearchPaths();
    const publicPath = publicSearchPaths[0]; // Use first public path
    const fullPath = `${publicPath}/${filename}`;

    const { bucketName, objectName } = parseObjectPath(fullPath);
    const bucket = objectStorageClient.bucket(bucketName);
    const file = bucket.file(objectName);

    // Determine content type from extension
    const contentTypeMap: { [key: string]: string } = {
      'jpg': 'image/jpeg',
      'jpeg': 'image/jpeg',
      'png': 'image/png',
      'gif': 'image/gif',
      'webp': 'image/webp',
    };
    const contentType = contentTypeMap[fileExtension.toLowerCase()] || 'image/jpeg';

    // Upload the file
    await file.save(buffer, {
      contentType,
      metadata: {
        cacheControl: 'public, max-age=31536000', // Cache for 1 year
      },
    });

    // Return the public URL path
    return `/public-objects/${filename}`;
  }

  // Save a base64-encoded video to object storage and return the public URL
  async saveBase64Video(base64Data: string, fileExtension: string = 'mp4'): Promise<string> {
    // Extract the base64 content (remove data URL prefix if present)
    const base64Match = base64Data.match(/^data:video\/\w+;base64,(.+)$/);
    const base64Content = base64Match ? base64Match[1] : base64Data;

    // Decode base64 to buffer
    const buffer = Buffer.from(base64Content, 'base64');

    // Generate unique filename in the public directory
    const filename = `shop/${randomUUID()}.${fileExtension}`;
    const publicSearchPaths = this.getPublicObjectSearchPaths();
    const publicPath = publicSearchPaths[0]; // Use first public path
    const fullPath = `${publicPath}/${filename}`;

    const { bucketName, objectName } = parseObjectPath(fullPath);
    const bucket = objectStorageClient.bucket(bucketName);
    const file = bucket.file(objectName);

    // Determine content type from extension
    const contentTypeMap: { [key: string]: string } = {
      'mp4': 'video/mp4',
      'webm': 'video/webm',
      'ogg': 'video/ogg',
      'mov': 'video/quicktime',
    };
    const contentType = contentTypeMap[fileExtension.toLowerCase()] || 'video/mp4';

    // Upload the file
    await file.save(buffer, {
      contentType,
      metadata: {
        cacheControl: 'public, max-age=31536000', // Cache for 1 year
      },
    });

    // Return the public URL path
    return `/public-objects/${filename}`;
  }
}

function parseObjectPath(path: string): {
  bucketName: string;
  objectName: string;
} {
  if (!path.startsWith("/")) {
    path = `/${path}`;
  }
  const pathParts = path.split("/");
  if (pathParts.length < 3) {
    throw new Error("Invalid path: must contain at least a bucket name");
  }

  const bucketName = pathParts[1];
  const objectName = pathParts.slice(2).join("/");

  return {
    bucketName,
    objectName,
  };
}

scripts/generate-pwa-icons.ts.content:
import sharp from 'sharp';
import fs from 'fs';
import path from 'path';

const sizes = [72, 96, 128, 144, 152, 192, 384, 512];
const iconsDir = path.join(process.cwd(), 'public', 'icons');

async function generateIcons() {
  console.log('Generating PWA icons...');

  // Read the 512x512 SVG as the base
  const svgPath = path.join(iconsDir, 'icon-512x512.svg');
  const svgBuffer = fs.readFileSync(svgPath);

  for (const size of sizes) {
    try {
      // Generate regular icon
      await sharp(svgBuffer)
        .resize(size, size)
        .png()
        .toFile(path.join(iconsDir, `icon-${size}x${size}.png`));

      console.log(`✓ Generated icon-${size}x${size}.png`);

      // Generate maskable icon (with padding for safe zone)
      const paddedSize = Math.round(size * 0.8); // 80% size leaves 10% safe zone on each side
      const padding = Math.round((size - paddedSize) / 2);

      await sharp({
        create: {
          width: size,
          height: size,
          channels: 4,
          background: { r: 37, g: 99, b: 235, alpha: 1 } // #2563eb
        }
      })
        .composite([{
          input: await sharp(svgBuffer).resize(paddedSize, paddedSize).png().toBuffer(),
          top: padding,
          left: padding
        }])
        .png()
        .toFile(path.join(iconsDir, `icon-${size}x${size}-maskable.png`));

      console.log(`✓ Generated icon-${size}x${size}-maskable.png`);
    } catch (error) {
      console.error(`Failed to generate ${size}x${size}:`, error);
    }
  }

  console.log('\n✨ All icons generated successfully!');
}

generateIcons().catch(console.error);

